import React from "react";

const ResultsTable = ({ results }) => {
  if (results.length === 0) {
    return <p className="no-results">No results found</p>;
  }

  return (
    <table>
      <thead>
        <tr>
          <th>Name</th>
          <th>Category</th>
          <th>Price ($)</th>
        </tr>
      </thead>
      <tbody>
        {results.map(item => (
          <tr key={item.id}>
            <td>{item.name}</td>
            <td>{item.category}</td>
            <td>{item.price}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
};

export default ResultsTable;
